      {
        "t": "Pas de badge télépéage"
      },
      {
        "t": "Pas de vignette Crit'Air"
      },
      {
        "t": "Tachy défaillant, infractions, surcharge",
        "ok": true
      },
      {
        "t": "Carte expirant sous un mois"
      }
