// ═══════════════════════════════════════════════════
// MOTEUR ADAPTATIF — QuestionEngine
// ═══════════════════════════════════════════════════
class QuestionEngine {
  constructor(bank) {
    this.bank = bank || [];
    this.history = this._loadHistory();
  }

  // Identifiant de l'utilisateur connecté (sessionStorage ou localStorage)
  _getUserId() {
    var stores = [];
    try { stores.push(sessionStorage); } catch(e) {}
    try { stores.push(localStorage); } catch(e) {}
    for (var s = 0; s < stores.length; s++) {
      var store = stores[s];
      for (var i = 0; i < store.length; i++) {
        var k = store.key(i);
        if (!k) continue;
        var raw = store.getItem(k);
        if (!raw) continue;
        try {
          var obj = JSON.parse(raw);
          var sess = obj.access_token ? obj : (obj.currentSession || null);
          if (sess && sess.user && sess.user.id) return sess.user.id;
        } catch(e2) {}
      }
    }
    return 'anonymous';
  }

  // Clé d'historique propre à chaque utilisateur
  _historyKey() {
    return 'ftr_q_history_' + this._getUserId();
  }

  _loadHistory() {
    try { return JSON.parse(localStorage.getItem(this._historyKey()) || '{}'); }
    catch(e) { return {}; }
  }

  _saveHistory() {
    try { localStorage.setItem(this._historyKey(), JSON.stringify(this.history)); }
    catch(e) {}
  }

  getByTheme(themeId) {
    return this.bank.filter(q => q.theme === themeId);
  }

  getThemeStats(themeId) {
    const qs = this.getByTheme(themeId);
    let seen = 0, correct = 0;
    qs.forEach(q => {
      const h = this.history[q.id];
      if (h) { seen++; correct += h.correct || 0; }
    });
    const pct = seen > 0 ? Math.round((correct / seen) * 100) : 0;
    return { seen, correct, total: qs.length, pct };
  }

  recordAnswer(qId, isCorrect) {
    if (!this.history[qId]) this.history[qId] = { seen: 0, correct: 0, wrong: 0 };
    this.history[qId].seen++;
    if (isCorrect) this.history[qId].correct++;
    else this.history[qId].wrong++;
    this._saveHistory();
  }

  getSmartSelection(themeId, count) {
    const pool = this.getByTheme(themeId);
    const scored = pool.map(q => {
      const h = this.history[q.id] || { seen: 0, wrong: 0 };
      let score = 1;
      if (h.seen === 0) score = 3;
      else if (h.wrong > 0) score = 2 + h.wrong;
      return { q, score };
    });
    scored.sort((a, b) => b.score - a.score + (Math.random() - 0.5) * 0.5);
    return scored.slice(0, count).map(s => s.q);
  }

  static shuffleAnswers(q) {
    const r = [...q.r];
    for (let i = r.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [r[i], r[j]] = [r[j], r[i]];
    }
    return { ...q, r };
  }
}
window.QuestionEngine = QuestionEngine;

